class MagixTranslation{constructor(){this.form=document.getElementById("edit_translations"),this.form&&this.initEvents()}initEvents(){this.form.addEventListener("submit",(e=>this.handleSubmit(e)))}async handleSubmit(e){e.preventDefault();const t=this.form.querySelector('button[type="submit"]'),n=t.innerHTML;t.innerHTML='<span class="spinner-border spinner-border-sm me-2"></span> Sauvegarde...',t.disabled=!0;const s=new FormData(this.form),a=""!==s.get("new_key").trim();try{const e=await fetch(this.form.action,{method:"POST",body:s}),t=await e.json();t.status?("undefined"!=typeof MagixToast&&MagixToast.success(t.message),a?setTimeout((()=>window.location.reload()),1e3):this.clearNewKeyInputs()):"undefined"!=typeof MagixToast&&MagixToast.error(t.message)}catch(e){console.error("Erreur AJAX:",e),"undefined"!=typeof MagixToast&&MagixToast.error("Une erreur de communication est survenue.")}finally{t.innerHTML=n,t.disabled=!1}}clearNewKeyInputs(){const e=this.form.querySelector('input[name="new_key"]');e&&(e.value="");this.form.querySelectorAll('input[name^="new_value"]').forEach((e=>e.value=""))}}document.addEventListener("DOMContentLoaded",(()=>{new MagixTranslation}));